    <div class="choice-toggle">故事分支</div>
    <div class="choice-panel">
      <div class="choice-content">
        <div class="choice-item">$1</div>
        <div class="choice-item">$2</div>
        <div class="choice-item">$3</div>
        <div class="choice-item">$4</div>
        <div class="choice-item">$5</div>
      </div>
      <div class="choice-footer">
        <div class="mode-switch">
          <button class="clear-btn">清除</button>
          <button class="mode-btn active" data-mode="single">单选</button>
          <button class="mode-btn" data-mode="multi">多选</button>
        </div>
      </div>
    </div>
