  <script>
    (function() {
      const container = document.querySelector('.choice-container');
      if (!container) return;

      const toggle = container.querySelector('.choice-toggle');
      const panel = container.querySelector('.choice-panel');
      const items = container.querySelectorAll('.choice-item');
      const modeBtns = container.querySelectorAll('.mode-btn');
      const clearBtn = container.querySelector('.clear-btn');

      let isMultiMode = false;
      let selectedTexts = [];

      toggle.addEventListener('click', function() {
        const isActive = panel.classList.contains('active');

        if (isActive) {
          panel.classList.remove('active');
        } else {
          panel.classList.add('active');

          items.forEach((item, index) => {
            item.style.animation = 'none';
            setTimeout(() => {
              item.style.animation = `itemSlideIn 0.4s ease-out forwards ${0.08 + index * 0.08}s`;
            }, 10);
          });
        }
      });

      modeBtns.forEach(btn => {
        btn.addEventListener('click', function(e) {
          e.stopPropagation();
          const mode = this.getAttribute('data-mode');
          isMultiMode = (mode === 'multi');

          modeBtns.forEach(b => b.classList.remove('active'));
          this.classList.add('active');

          if (!isMultiMode) {
            selectedTexts = [];
            items.forEach(item => item.classList.remove('selected'));
            clearBtn.classList.remove('show');
          }
        });
      });

      clearBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        selectedTexts = [];
        items.forEach(item => item.classList.remove('selected'));
        this.classList.remove('show');

        try {
          const input = window.parent.document.querySelector('#send_textarea');
          if (input) {
            input.value = '';
            input.dispatchEvent(new Event('input', { bubbles: true }));
          }
        } catch (error) { 
          console.error('SillyTavern Regex Error:', error); 
        }
      });

      items.forEach(item => {
        item.addEventListener('click', function() {
          const choiceText = this.textContent.trim();

          try {
            const input = window.parent.document.querySelector('#send_textarea');
            if (!input) return;

            if (isMultiMode) {
              const index = selectedTexts.indexOf(choiceText);

              if (index > -1) {
                selectedTexts.splice(index, 1);
                this.classList.remove('selected');
              } else {
                selectedTexts.push(choiceText);
                this.classList.add('selected');
              }

              input.value = selectedTexts.join('\n');
              input.dispatchEvent(new Event('input', { bubbles: true }));

              if (selectedTexts.length > 0) {
                clearBtn.classList.add('show');
              } else {
                clearBtn.classList.remove('show');
              }

            } else {
              items.forEach(i => i.classList.remove('selected'));
              this.classList.add('selected');

              input.value = choiceText;
              input.dispatchEvent(new Event('input', { bubbles: true }));

              setTimeout(() => {
                panel.classList.remove('active');
              }, 200);
            }
          } catch (error) { 
            console.error('SillyTavern Regex Error:', error); 
          }
        });
      });

      document.addEventListener('click', function(e) {
        if (!container.contains(e.target)) {
          panel.classList.remove('active');
        }
      });
    })();
  </script>
