            var rawTitle = (root.querySelector('[data-nh-raw-title]').textContent || '').trim();
            var chapterMatch = rawTitle.match(
                /^(第.+?章|Chapter\s+\w+|卷\w+|[Vv]ol(?:\.|ume)\s*\w+|[Pp]art\s+\w+|[Ee]p(?:\.|isode)\s*\w+|#\s*\d+)\s*[·.\-—:：\s]\s*([\s\S]*)$/i
            );

            if (chapterMatch) {
                chapterEl.textContent = chapterMatch[1];
                titleEl.textContent = chapterMatch[2] || '';
            } else {
                chapterEl.style.display = 'none';
                titleEl.textContent = rawTitle;
            }

            var rawPrologue = root.querySelector('[data-nh-raw-prologue]').innerHTML || '';
            var hrParts = rawPrologue.split(/<hr\s*\/?>/i);
            var isDual = hrParts.length > 1;

            function extractSource(text) {
                var lines = text.trim().split('\n');
                var last = (lines[lines.length - 1] || '').trim();
                if (/^[—―─\-–]/.test(last)) {
                    lines.pop();
                    return { body: lines.join('\n').trim(), source: last.replace(/^[—―─\-–]\s*/, '') };
                }
                return { body: text.trim(), source: '' };
            }

            function cleanQuotes(text) {
                return text.trim()
                    .split('\n')
                    .map(function (l) {
                        return l.trim().replace(/^[""「『]/, '').replace(/[""」』]$/, '');
                    })
                    .filter(Boolean)
                    .join('<br>');
            }

            var html = '';

            if (isDual) {
                var originalText = cleanQuotes(hrParts[0]);
                var parsed = extractSource(hrParts.slice(1).join(''));
                var translationText = cleanQuotes(parsed.body);

                if (originalText) html += '<div class="nh3-quote-original">' + originalText + '</div>';
                if (translationText) html += '<div class="nh3-quote-translation">' + translationText + '</div>';
                if (parsed.source) html += '<span class="nh3-source">' + parsed.source + '</span>';
            } else {
                var parsed = extractSource(rawPrologue);
                var soloText = cleanQuotes(parsed.body);

                if (soloText) html += '<div class="nh3-quote-solo">' + soloText + '</div>';
                if (parsed.source) html += '<span class="nh3-source">' + parsed.source + '</span>';
            }

            prologueEl.innerHTML = html;
            applyPalette(currentMode);

        })();
    </script>
